package com.mdweb.tunnumerique.tools.mdwebNetworkingLib.cache;import android.content.Context;import android.graphics.Bitmap;import android.graphics.drawable.BitmapDrawable;import android.os.Build;import android.util.Log;import android.view.ViewGroup;import androidx.collection.LruCache;import com.android.volley.toolbox.ImageLoader;/** * Created by Slim Tonnech. */public class BitmapMemoryCache extends LruCache<String, Bitmap> implements ImageLoader.ImageCache {	private Context context;	public void setContext(Context context) {		this.context = context;	}	public BitmapMemoryCache() {		this(getDefaultLruCacheSize());	}	public BitmapMemoryCache(int sizeInKiloBytes) {		super(sizeInKiloBytes);	}	@Override	protected int sizeOf(String key, Bitmap value) {		return value.getRowBytes() * value.getHeight() / 1024;	}	@Override	public Bitmap getBitmap(String url) {		return get(url);	}	@Override	public void putBitmap(String url, Bitmap bitmap) {		put(url, bitmap);	}	public static int getDefaultLruCacheSize() {		final int maxMemory =				(int) (Runtime.getRuntime().maxMemory() / 1024);		return maxMemory / 8;	}	public void addBitmapToMemoryCache(String key, Bitmap bitmap) {		if (getBitmapFromMemCache(key) == null) {			putBitmap(key, bitmap);		}	}	public Bitmap getBitmapFromMemCache(String key) {		return get(key);	}	public void loadBitmap(int resId, ViewGroup view) {		final String imageKey = String.valueOf(resId);		final Bitmap bitmap = getBitmapFromMemCache(imageKey);		if (bitmap != null) {			Log.d("bitmp","!null");			if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.JELLY_BEAN) {				view.setBackground(new BitmapDrawable(context.getResources(), bitmap));			}		} else {			Log.d("bitmp","null");			BitmapWorkerTask task = new BitmapWorkerTask(view,context,this);			task.execute(resId);		}	}}